1	const PROCESSING_FEE = 5;
2	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
3	  sword: 100,
4	  amulet: 60,
5	  staff: 80,
6	  potion: 40,
7	  rune: 25,
8	};
9	
10	type Item = { type: string };
11	type Step = { type: string; items: Item[] };
12	
13	export function runScenario(steps: Step[]): unknown[] {
14	  return steps.map((step) => ({
15	    premium:
16	      PROCESSING_FEE +
17	      step.items.reduce(
18	        (sum, item) => sum + BASE_PREMIUM_BY_TYPE[item.type],
19	        0,
20	      ),
21	  }));
22	}
